using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Primitives;

namespace WebhookProxy
{
    [ApiController]
    [Route("[controller]")]
    public class WebhooksController : ControllerBase
    {
        [HttpPost("{id}")]
        public async Task<IActionResult> Post(string id, [FromBody] StringValues body)
        {
            var url = Request.Query["url"];
            if (string.IsNullOrEmpty(url))
                return BadRequest("Missing 'url' query parameter.");

            using (var httpClient = new HttpClient())
            {
                var requestUri = new Uri(new Uri(url), id);
                await httpClient.PostAsync(requestUri, new StringContent(body.ToString(), System.Text.Encoding.UTF8, "application/json"));

                var response = await httpClient.GetAsync(requestUri);
                return Ok(await response.Content.ReadAsStringAsync());
            }
        }
    }
